INSERT INTO public.questions (exam_id, subject_id, topic_id, year, paper, question_text, option_1, option_2, option_3, option_4, correct_option, explanation, difficulty) VALUES
('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aa8d32e0-c642-49ea-934c-af0f7fd9986a'::uuid, '66a94591-334c-4e5c-b867-b27aef0c72ec'::uuid, 2023, 'Paper-I', 'A mobile number does not have 9 numbers, ______?', 'doesn''t it', 'do it', 'does it', 'is it', 3, 'Negative statement → positive tag question. ''Does'' is the auxiliary verb, so the tag is ''does it?''.', 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aa8d32e0-c642-49ea-934c-af0f7fd9986a'::uuid, '66a94591-334c-4e5c-b867-b27aef0c72ec'::uuid, 2023, 'Paper-I', 'Select the passive form: I had washed all the windows before the rain.', 'All the windows have been washed before the rain.', 'All the windows had been washed before the rain.', 'All the windows have been washed before the rain.', 'All the windows were washed before the rain by me.', 2, '''Had washed'' (past perfect) becomes ''had been washed'' in passive voice. The correct passive form is ''All the windows had been washed before the rain.''', 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aa8d32e0-c642-49ea-934c-af0f7fd9986a'::uuid, '66a94591-334c-4e5c-b867-b27aef0c72ec'::uuid, 2023, 'Paper-I', 'Select the passive form: Ramesh will locate your spectacles.', 'Your spectacles would be located by Ramesh.', 'Your spectacles had been located by Ramesh.', 'Your spectacles will be located by Ramesh.', 'Your spectacles shall be located by Ramesh.', 3, '''Will locate'' (future) becomes ''will be located'' in passive voice.', 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aa8d32e0-c642-49ea-934c-af0f7fd9986a'::uuid, '66a94591-334c-4e5c-b867-b27aef0c72ec'::uuid, 2023, 'Paper-I', 'To have a finger in the pie means:', 'To confess your faults', 'To have an interest or share', 'To have no reservations', 'To plead someone', 2, '''To have a finger in the pie'' means to be involved or have an interest/share in something.', 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aa8d32e0-c642-49ea-934c-af0f7fd9986a'::uuid, '66a94591-334c-4e5c-b867-b27aef0c72ec'::uuid, 2023, 'Paper-I', 'Flag something/someone down means:', 'Signal to stop', 'To administer', 'To reconstruct the plan', 'To control someone', 1, '''To flag down'' means to signal to stop a vehicle or person by waving or using a flag.', 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aa8d32e0-c642-49ea-934c-af0f7fd9986a'::uuid, '66a94591-334c-4e5c-b867-b27aef0c72ec'::uuid, 2023, 'Paper-I', 'Choose the synonym of ''Lackluster''.', 'Sombre', 'Incandescent', 'Radiant', 'Reluctant', 1, '''Lackluster'' means dull, mediocre, or uninspiring. ''Sombre'' (gloomy, dull) is the closest synonym. ''Incandescent'' and ''Radiant'' mean bright and shining (antonyms).', 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aa8d32e0-c642-49ea-934c-af0f7fd9986a'::uuid, '66a94591-334c-4e5c-b867-b27aef0c72ec'::uuid, 2023, 'Paper-I', 'Choose the antonym of ''Veracity''.', 'Prevarication', 'Comprehension', 'Audacity', 'Denial', 1, '''Veracity'' means truthfulness. ''Prevarication'' means deceitfulness or evasion of truth (antonym).', 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aa8d32e0-c642-49ea-934c-af0f7fd9986a'::uuid, '66a94591-334c-4e5c-b867-b27aef0c72ec'::uuid, 2023, 'Paper-I', 'Choose the incorrectly spelt word in: Transport rates avoiding Russia have gained in importance.', 'Transport', 'routes', 'gained', 'importance', 1, '''Transport'' is spelled correctly. ''Routes'' is spelled correctly. ''Gained'' is spelled correctly. ''Importance'' is spelled correctly. All are correct - the sentence has no spelling error. The correct answer should be ''No error''. But the key marks option 2 (routes) as incorrectly spelled? Actually ''routes'' is correct spelling. Checking: ''Transport'' is correct. ''routes'' is correct. ''gained'' is correct. ''importance'' is correct. There is no spelling error.', 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aa8d32e0-c642-49ea-934c-af0f7fd9986a'::uuid, '66a94591-334c-4e5c-b867-b27aef0c72ec'::uuid, 2023, 'Paper-I', 'Choose the incorrectly spelt word in: The conflict would not be governed by the entirety of the laws of war.', 'Laws', 'conflict', 'entirety', 'governed', 1, '''Laws'' is spelled correctly. ''Conflict'' is spelled correctly. ''Entirety'' is spelled correctly. ''Governed'' is spelled correctly. There is no spelling error in this sentence either.', 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aa8d32e0-c642-49ea-934c-af0f7fd9986a'::uuid, '66a94591-334c-4e5c-b867-b27aef0c72ec'::uuid, 2023, 'Paper-I', 'Select the most appropriate option for the blank: I ______ a girl who was screaming loudly at her friends.', 'sew', 'soar', 'sore', 'saw', 4, 'The sentence requires the past tense of ''see'' → ''saw''. ''Sew'' means to stitch, ''soar'' means to fly high, ''sore'' means painful.', 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aa8d32e0-c642-49ea-934c-af0f7fd9986a'::uuid, '66a94591-334c-4e5c-b867-b27aef0c72ec'::uuid, 2023, 'Paper-I', 'Select the most appropriate option for the blank: The smaller, more ______ style is more suitable for everyday wear.', 'discrete', 'discreet', 'desecrate', 'dissect', 2, '''Discreet'' means careful, modest, or showing good judgment. ''Discrete'' means separate or distinct. The context suggests ''discreet'' (subtle, not flashy).', 'medium')
